import { useState } from "react";
import { ChevronDown } from "lucide-react";

function enhanceShortAnswer(q: string, a: string) {
  const answer = a.trim();
  if (answer.length >= 170) return answer;

  const text = `${q} ${answer}`.toLowerCase();

  if (/mortgage|loan|debt|credit|payment|apr|refinance|lease|payoff|amortization/.test(text)) {
    return `${answer} For a more reliable estimate, compare the payment with the total interest, the payoff time, and any fees that may not appear in the headline rate. Small changes in rate, term, or extra payment amount can shift the lifetime cost by hundreds or thousands of dollars, so it is worth testing more than one scenario before making a borrowing decision.`;
  }

  if (/tax|salary|paycheck|take-home|income|marriage|estate/.test(text)) {
    return `${answer} The most important detail is whether you are entering gross income, taxable income, or after-tax income, because each one produces a different result. Filing status, deductions, credits, state rules, and payroll taxes can all change the final number, so use the calculator as a planning estimate and compare it with official tax forms or a qualified professional when the decision is important.`;
  }

  if (/retirement|pension|401|ira|rmd|annuity|social security/.test(text)) {
    return `${answer} Retirement estimates are strongest when you review the assumptions behind the answer, including years of service, contribution rate, expected return, claiming age, inflation, and taxes. A small change in time horizon or benefit formula can create a large difference over decades, so rerun the calculation with conservative and optimistic inputs before using it in a long-term plan.`;
  }

  if (/investment|interest|compound|savings|return|roi|irr|bond|cd|present value|future value|payback/.test(text)) {
    return `${answer} To interpret the result well, look beyond the final number and compare the starting value, growth rate, compounding period, fees, and time horizon. Investment and savings projections are estimates, not guarantees, so it helps to test lower-return and higher-return cases and consider inflation before deciding whether the outcome fits your goal.`;
  }

  if (/budget|rent|house|home|real estate|property|down payment/.test(text)) {
    return `${answer} The result is most useful when you include recurring costs and irregular expenses instead of only the obvious monthly payment. Housing, utilities, maintenance, insurance, debt payments, and savings goals all compete for the same income, so a comfortable answer should leave room for emergencies and not just balance on paper.`;
  }

  if (/bmi|body|calorie|protein|carb|fat|tdee|bmr|heart|pregnancy|gfr|bac|weight|health/.test(text)) {
    return `${answer} Health calculators are best used as educational screening tools, not as a diagnosis or a replacement for medical care. Enter measurements carefully, keep units consistent, and consider the result alongside symptoms, history, and professional guidance, especially if the number affects medication, pregnancy, nutrition, or safety decisions.`;
  }

  if (/youtube|tiktok|instagram|social|influencer|twitter|pinterest|bio link|engagement|creator/.test(text)) {
    return `${answer} Social and creator metrics can vary widely by niche, audience quality, posting format, and platform rules, so the result should be read as a decision aid rather than a fixed promise. For better planning, compare the output with recent real posts, audience demographics, engagement quality, and the value of any brand, affiliate, or traffic outcome connected to the calculation.`;
  }

  if (/science|chemistry|physics|atom|mole|molar|force|density|momentum|voltage|resistor|ohm|kinetic|velocity|pressure/.test(text)) {
    return `${answer} For the cleanest result, keep units consistent, check significant figures, and confirm which formula matches the problem you are solving. The calculator can speed up classwork, lab checks, and quick comparisons, but the final interpretation still depends on choosing the right inputs and understanding what each variable represents.`;
  }

  if (/percent|fraction|average|mean|median|standard deviation|z score|triangle|circle|matrix|math/.test(text)) {
    return `${answer} Math results are easiest to trust when the input values are typed in the same format and the method matches the question being asked. Use the answer together with the shown steps or surrounding explanation so you understand the process, not just the final number, especially for homework, checking work, or comparing scenarios.`;
  }

  return `${answer} For best results, enter current numbers, keep units consistent, and review the supporting details before relying on the output. The calculator is meant to give a fast practical estimate, so rerun it with a few different assumptions when the decision involves money, health, safety, schoolwork, or a long-term commitment.`;
}

export default function FAQItem({ q, a }: { q: string; a: string }) {
  const [open, setOpen] = useState(false);
  const answer = enhanceShortAnswer(q, a);

  return (
    <div
      className={`border rounded-2xl overflow-hidden transition-all duration-200 ${
        open
          ? "border-primary/30 bg-primary/[0.025] dark:bg-primary/[0.04] shadow-sm"
          : "border-border bg-card hover:border-primary/20 hover:shadow-sm"
      }`}
    >
      <button
        className="w-full flex items-center justify-between px-4 sm:px-5 py-4 text-left gap-4"
        onClick={() => setOpen(o => !o)}
        aria-expanded={open}
      >
        <h3 className="text-sm sm:text-base font-semibold text-foreground leading-snug">{q}</h3>
        <span
          className={`flex-shrink-0 w-7 h-7 rounded-full border flex items-center justify-center transition-all duration-200 ${
            open
              ? "bg-primary border-primary text-primary-foreground -rotate-180"
              : "bg-muted border-border text-muted-foreground"
          }`}
        >
          <ChevronDown className="w-3.5 h-3.5" />
        </span>
      </button>
      <div
        className={`grid transition-all duration-300 ease-out ${
          open ? "grid-rows-[1fr]" : "grid-rows-[0fr]"
        }`}
      >
        <div className="overflow-hidden">
          <div className="px-4 sm:px-5 pb-4 sm:pb-5">
            <div className="border-t border-border/50 pt-3 text-sm text-muted-foreground leading-relaxed">
              {answer}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}
